/* ===========================================================================
 *  autogenerated-element-type.c -- BoltOS replacement for the gperf-generated
 *  HTML element-name -> element_type table (gperf is not available in this
 *  toolchain). Same public interface the upstream gperf output provides:
 *  a `wordlist[]` table (read by element_type_to_name) and a case-insensitive
 *  `hubbub_element_type_generated_lookup(str,len)`. Behaviour-equivalent; only
 *  the lookup is a linear scan instead of a perfect hash.
 * ===========================================================================*/
#include <string.h>
#include <strings.h>
#include "treebuilder/element-type.h"

