const struct element_type_map *hubbub_element_type_generated_lookup(
        register const char *str, register size_t len)
{
    for (size_t i = 0; i < sizeof(wordlist) / sizeof(wordlist[0]); i++) {
        if (strlen(wordlist[i].name) == len &&
            strncasecmp(str, wordlist[i].name, len) == 0)
            return &wordlist[i];
    }
    return (const struct element_type_map *)0;
}
